import fs from 'node:fs/promises';
import { JSDOM } from 'jsdom';

const dir = '/tmp/codexdesktop-tasks/browser-automation-pricing-20260709';
const evidencePath = "'`${dir}/evidence.jsonl`;
const metricsPath = `${dir}/metrics.json`;
const observedAt = new Date().toISOString();

const urls = [
  ['"'browserbase_pricing','Browserbase pricing','https://www.browserbase.com/pricing'],
  ['browserbase_docs_limits','Browserbase limits docs','https://docs.browserbase.com/platform/limits'],
  ['browserbase_sessions','Browserbase sessions docs','https://docs.browserbase.com/platform/sessions'],
  ['browserless_pricing','Browserless pricing','https://www.browserless.io/pricing'],
  ['browserless_docs_limits','Browserless docs usage limits','https://docs.browserless.io/baas/usage-limits'],
  ['browserless_docs_options','Browserless browser options','https://docs.browserless.io/baas/chrome-flags'],
  ['steel_pricing','Steel pricing','https://steel.dev/pricing'],
  ['steel_docs_sessions','Steel sessions docs','https://docs.steel.dev/overview/sessions'],
  ['steel_docs_api','Steel API docs','https://docs.steel.dev/api-reference/sessions/create']
];

function cleanText(html) {
  const dom = new JSDOM(html);
  for (const el of dom.window.document.querySelectorAll('script,style,svg,noscript')) el.remove();
  return dom.window.document.body?.textContent?.replace(/\\s+/g,' ').trim() || '';
}
function snippets(text, terms) {
  const out = [];
  const lower = text.toLowerCase();
  for (const term of terms) {
    const idx = lower.indexOf(term.toLowerCase());
    if (idx >= 0) out.push(text.slice(Math.max(0, idx-220), Math.min(text.length, idx+520)));
  }
  return [...new Set(out)].slice(0, 8);
}
async function fetchOne(id,title,url) {
  const rec = { id, source:title, url, sourceType:'primary', observedAt, status:'', title:'', claim:'', snippets:[], caveat:'' };
  try {
    const res = await fetch(url, { headers: { 'user-agent': 'Mozilla/5.0 Codex research bot' } });
    rec.status = "'`${res.status} ${res.statusText}`;
    rec.finalUrl = res.url;
    const html = await res.text();
    const text = cleanText(html);
    rec.title = (html.match(/<title[''^>]*>([''^<]*)/i)?.[1] || title).trim();
    rec.textSample = text.slice(0, 800);
    rec.snippets = snippets(text, ['"'"'$'"','month','session','concurrent','limit','credit','minute','hour','browser','proxy','captcha','stealth','10,000','10000']);
    rec.claim = rec.snippets.join(' | ').slice(0, 3500);
    if ("'!text || text.length < 200) rec.caveat = '"'Low text extraction; page may be client-rendered.';
  } catch(e) {
    rec.status = 'error'; rec.caveat = e.message;
  }
  return rec;
}

await fs.writeFile(evidencePath, '');
const records = [];
for (const u of urls) {
  const rec = await fetchOne(...u);
  records.push(rec);
  await fs.appendFile(evidencePath, JSON.stringify(rec) + '\\n');
}
const gaps = records.filter(r => r.status.startsWith('error') || r.caveat).map(r => ({id:r.id, status:r.status, caveat:r.caveat}));
await fs.writeFile(metricsPath, JSON.stringify({ observedAt, records: records.length, gaps }, null, 2));
console.log(JSON.stringify({ ok:true, records: records.length, gaps, artifacts:{ evidence:evidencePath, metrics:metricsPath } }));
EOF
